prompt --application/pages/page_00004
begin
wwv_flow_imp_page.create_page(
 p_id=>4
,p_name=>'Detalle Bares'
,p_alias=>'DETALLE-BARES'
,p_step_title=>'Detalle Bares'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-zu3n.onrender.com/bares''; // URL de su API en Render',
'const barId = parseInt(apex.item(''BAR_ID'').getValue().split('':''[0]));',
'function cargarComentarios() {',
'console.log(barId);',
'fetch(`${API_BASE}/${barId}/comentarios`)',
'.then(res => res.json())',
'.then(data => {',
'console.log(data);',
'const container = document.getElementById(''comentarios-container'');',
'if (data.length === 0) {',
unistr('container.innerHTML = ''<p>No hay comentarios a\00FAn. \00A1S\00E9 el primero!</p>'';'),
'return;',
'}',
'container.innerHTML = data.map(c => `',
'<div style="border:1px solid #ddd; border-radius:8px;',
'padding:12px; margin-bottom:10px;">',
unistr('<strong>${c.usuario || ''An\00F3nimo''}</strong>'),
'<span style="color:#888; font-size:0.85em; margin-',
'left:10px;">',
'${JSON.stringify(c.fecha)}',
'</span>',
'<p style="margin-top:6px;">${c.comentario}</p>',
'<p>',
unistr('Calificaci\00F3n: ${c.calificacion || ''Sin calificaci\00F3n''}'),
'</p>',
'</div>',
'`).join('''');',
'})',
'.catch(err => {',
'document.getElementById(''comentarios-container'').innerHTML =',
'''<p style="color:red;">Error cargando comentarios.</p>'';',
'});',
'}',
'',
'function enviarComentario() {',
'const comentario = apex.item(''COMENTARIO'').getValue();',
'const calificacion = apex.item(''CALIFICACION'').getValue();',
'if (!comentario.trim()) {',
unistr('apex.message.showErrors([{ message: ''El comentario no puede estar vac\00EDo.'' }]);'),
'return;',
'}',
'',
'console.log({',
'    comentario,',
'    calificacion,',
'    barId',
'});',
'',
'if (!comentario.trim()) {',
'',
'    apex.message.showErrors([',
'        {',
'            type: "error",',
'            location: "page",',
unistr('            message: "El comentario no puede estar vac\00EDo.",'),
'            unsafe: false',
'        }',
'    ]);',
'',
'    return;',
'}',
'',
'console.log(apex.env);',
'console.log(apex.env.APP_USER);',
'',
'',
'fetch(`${API_BASE}/${barId}/comentarios`, {',
'method: ''POST'',',
'headers: { ''Content-Type'': ''application/json'' },',
'body: JSON.stringify({',
'comentario: comentario,',
unistr('usuario: apex.env.APP_USER, // usuario de sesi\00F3n APEX'),
'calificacion: parseInt(calificacion)',
'})',
'})',
'.then(async res => {',
'',
'    console.log("STATUS:", res.status);',
'',
'    const data = await res.json();',
'',
'    console.log("RESPONSE:", data);',
'',
'    if (!res.ok) {',
'        throw new Error(JSON.stringify(data));',
'    }',
'',
'    return data;',
'    })',
'',
'.then(data => {',
'',
'    console.log("Comentario insertado");',
'',
'    apex.item(''CALIFICACION'').setValue('''');',
'',
'    apex.item(''COMENTARIO'').setValue('''');',
'',
'    cargarComentarios();',
'',
'})',
' ',
'',
'.catch(err => {',
'    console.error(err);',
'',
'apex.message.showErrors([{ message: ''Error enviando el comentario.'' }]);',
'});',
'}'))
,p_javascript_code_onload=>'cargarComentarios();'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'03'
,p_last_updated_by=>'CO_B331_SQL_S71'
,p_last_upd_yyyymmddhh24miss=>'20260513231529'
);
