prompt --application/pages/page_00006
begin
wwv_flow_imp_page.create_page(
 p_id=>6
,p_name=>'Ver eventos'
,p_alias=>'VER-EVENTOS'
,p_step_title=>'Ver eventos'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-zu3n.onrender.com/bares''; ',
'',
'function cargarEventos() {',
'    const barId = parseInt(apex.item(''P5_BAR_ID'').getValue());',
'    if (!barId) return;',
'',
'    fetch(`${API_BASE}/${barId}/eventos`)',
'        .then(res => res.json())',
'        .then(data => {',
'            const container = document.getElementById(''eventos-container'');',
'            if (data.length === 0) {',
unistr('                container.innerHTML = ''<p>No hay eventos programados a\00FAn.</p>'';'),
'                return;',
'            }',
'            ',
'            container.innerHTML = data.map(e => {',
'                let camposDinamicos = '''';',
'                ',
'                // Recorremos el JSON. Si encuentra un sub-objeto (como detalles_adicionales), lo desglosa.',
'                for (const [clave, valor] of Object.entries(e)) {',
'                    if (clave !== ''nombre_evento'' && clave !== ''fecha_evento'' && clave !== ''_id'' && clave !== ''bar_id_oracle'') {',
'                        ',
'                        if (typeof valor === ''object'' && valor !== null) {',
'                            // Es un sub-objeto (ej. detalles_adicionales)',
'                            const tituloSeccion = clave.replace(''_'', '' '').toUpperCase();',
'                            camposDinamicos += `<p style="margin:8px 0 3px 0; font-size:13px; color:#555;"><strong>${tituloSeccion}</strong></p>`;',
'                            ',
'                            // Recorremos lo que hay dentro del sub-objeto',
'                            for (const [subClave, subValor] of Object.entries(valor)) {',
'                                const etiqueta = subClave.charAt(0).toUpperCase() + subClave.slice(1).replace(''_'', '' '');',
unistr('                                camposDinamicos += `<p style="margin:2px 0 2px 15px; font-size:14px;">\21B3 <strong>${etiqueta}:</strong> ${subValor}</p>`;'),
'                            }',
'                        } else {',
unistr('                            // Es un campo normal en la ra\00EDz'),
'                            const etiqueta = clave.charAt(0).toUpperCase() + clave.slice(1).replace(''_'', '' '');',
'                            camposDinamicos += `<p style="margin:3px 0; font-size:14px;"><strong>${etiqueta}:</strong> ${valor}</p>`;',
'                        }',
'                    }',
'                }',
'',
'                return `',
'                <div style="border:1px solid #c0c0c0; border-radius:8px; padding:15px; margin-bottom:15px; background-color: #fafafa; box-shadow: 2px 2px 5px rgba(0,0,0,0.05);">',
'                    <h3 style="margin:0; color:#005ea5; font-size: 18px;">${e.nombre_evento || ''Evento sin nombre''}</h3>',
'                    <p style="color:#777; font-size:12px; margin:5px 0 10px 0;">',
unistr('                        \D83D\DDD3\FE0F ${e.fecha_evento ? new Date(e.fecha_evento).toLocaleString(''es-CO'') : ''Fecha no registrada''}'),
'                    </p>',
'                    ',
'                    <div style="border-top: 1px solid #eee; padding-top: 10px;">',
'                        ${camposDinamicos}',
'                    </div>',
'',
'                    <details style="margin-top:12px; cursor:pointer;">',
'                        <summary style="color:#d2322d; font-weight:bold; font-size:13px; outline:none;"> Ver JSON Original</summary>',
'                        <pre style="background-color:#2b2b2b; color:#a9b7c6; padding:10px; border-radius:5px; margin-top:8px; font-size:12px; overflow-x:auto;">${JSON.stringify(e, null, 4)}</pre>',
'                    </details>',
'                </div>',
'                `;',
'            }).join('''');',
'        })',
'        .catch(err => {',
unistr('            document.getElementById(''eventos-container'').innerHTML = ''<p style="color:red;">Error de conexi\00F3n con la API.</p>'';'),
'        });',
'}',
'',
'function enviarEvento() {',
'    const barId = parseInt(apex.item(''P5_BAR_ID'').getValue());',
'    const nombre = apex.item(''P5_NOMBRE_EVENTO'').getValue();',
'    const tipo = apex.item(''P5_TIPO_EVENTO'').getValue();',
'',
'    if (!barId || !nombre.trim()) {',
'        apex.message.showErrors([{ message: ''El ID del Bar y el Nombre del evento son obligatorios.'', location: "page" }]);',
'        return;',
'    }',
'',
unistr('    // 1. Construimos el JSON base con la ra\00EDz'),
'    const payload = {',
'        bar_id_oracle: barId,',
'        nombre_evento: nombre',
'    };',
'',
unistr('    // 2. Creamos un sub-objeto vac\00EDo para los detalles'),
'    const detalles = {};',
'',
unistr('    // 3. Llenamos el sub-objeto seg\00FAn el tipo de evento'),
'    if (tipo === ''CONCIERTO'') {',
'        const artista = apex.item(''P5_ARTISTA'').getValue();',
'        const cover = apex.item(''P5_COVER'').getValue();',
'        ',
'        // Si queremos que ''artistas'' sea un arreglo como en tu JSON original',
'        if (artista) detalles.artistas = [artista]; ',
'        if (cover) detalles.cover = parseFloat(cover);',
'        ',
'    } else if (tipo === ''HAPPY_HOUR'') {',
'        const descuento = apex.item(''P5_DESCUENTO'').getValue();',
'        const horaInicio = apex.item(''P5_HORA_INICIO'').getValue();',
'        ',
'        if (descuento) detalles.descuento = descuento;',
'        if (horaInicio) detalles.hora_inicio = horaInicio;',
'    }',
'',
unistr('    // 4. S\00D3LO agregamos el bloque "detalles_adicionales" al payload si tiene al menos un dato adentro'),
'    if (Object.keys(detalles).length > 0) {',
'        payload.detalles_adicionales = detalles;',
'    }',
'',
'    // 5. Enviamos a la API',
'    fetch(`${API_BASE}/${barId}/eventos`, {',
'        method: ''POST'',',
'        headers: { ''Content-Type'': ''application/json'' },',
'        body: JSON.stringify(payload)',
'    })',
'    .then(res => res.json())',
'    .then(() => {',
'        apex.item(''P5_NOMBRE_EVENTO'').setValue('''');',
'        apex.item(''P5_ARTISTA'').setValue('''');',
'        apex.item(''P5_COVER'').setValue('''');',
'        apex.item(''P5_DESCUENTO'').setValue('''');',
'        apex.item(''P5_HORA_INICIO'').setValue('''');',
'        ',
'        apex.message.clearErrors(); ',
'        cargarEventos(); ',
'    })',
'    .catch(() => {',
'        apex.message.showErrors([{ message: ''Error guardando el evento.'', location: "page" }]);',
'    });',
'}'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'17'
,p_last_updated_by=>'TOMASGALARZA'
,p_last_upd_yyyymmddhh24miss=>'20260517014318'
);
